-- Zoo 2: Animal Park catalog — generated from the Google Sheet (zoo2_animals)
-- Idempotent: upsert on name_en.

on conflict (name_en) do update set
  name_fr = excluded.name_fr,
  biome = excluded.biome,
  shelter_lvl = excluded.shelter_lvl,
  variant = excluded.variant,
  price_value = excluded.price_value,
  price_unit = excluded.price_unit,
  size = excluded.size,
  breed_proba = excluded.breed_proba,
  breed_cost = excluded.breed_cost,
  breed_duration = excluded.breed_duration,
  xp_feeding_value = excluded.xp_feeding_value,
  xp_feeding_time = excluded.xp_feeding_time,
  xp_playing_value = excluded.xp_playing_value,
  xp_playing_time = excluded.xp_playing_time,
  xp_cleaning_value = excluded.xp_cleaning_value,
  xp_cleaning_time = excluded.xp_cleaning_time,
  max_animal_per_enclosure = excluded.max_animal_per_enclosure,
  popularity = excluded.popularity,
  base_selling_price = excluded.base_selling_price,
  wiki_title = excluded.wiki_title,
  url = excluded.url;
